#nullable enable // autogenerated

using MVZ2.GameContent.Armors;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Level;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Enemies
{
    [EntityBehaviourDefinition(VanillaEnemyNames.skeletonWarrior)]
    public class SkeletonWarrior : AIEntityBehaviour
    {
        public SkeletonWarrior(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            if (entity.Level.IsIZombie())
            {
                entity.AddBuff<IZombieSkeletonWarriorBuff>();
                var helmet = entity.GetMainArmor();
                var shield = entity.GetArmorAtSlot(VanillaArmorSlots.shield);
                helmet?.AddBuff<IZombieSkeletonWarriorArmorBuff>();
                shield?.AddBuff<IZombieSkeletonWarriorArmorBuff>();
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelDamagePercent();

            if (entity.State == STATE_MELEE_ATTACK)
            {
                // Ļ•Ľų Ī‘Ųľ”ľű…ňbuff  
                if (!entity.HasBuff<WarriorResistance>())
                {
                    var buff = entity.AddBuff<WarriorResistance>();
                    buff.SetProperty(WarriorResistance.PROP_Resistance_Level, 0.25f);
                }
            }
            else
            {
                // ≤ĽĻ•Ľų Ī»•≥żľű…ňbuff  
                if (entity.HasBuff<WarriorResistance>())
                {
                    entity.RemoveBuffs<WarriorResistance>();
                }
            }

        }
        public const int STATE_MELEE_ATTACK = VanillaEnemyStates.MELEE_ATTACK;
    }
}
